'use client';

import { useState, useEffect } from 'react';
import { createClient } from '@supabase/supabase-js';

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL || '',
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || ''
);

export default function Home() {
  const [currentPage, setCurrentPage] = useState('main');
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const saved = sessionStorage.getItem('currentUser');
    if (saved) {
      setCurrentUser(JSON.parse(saved));
      setCurrentPage('store');
    }
  }, []);

  const handleLogout = () => {
    setCurrentUser(null);
    sessionStorage.clear();
    setCurrentPage('main');
  };

  const pages: any = {
    main: <MainPage setCurrentPage={setCurrentPage} />,
    login: <LoginPage setCurrentPage={setCurrentPage} setCurrentUser={setCurrentUser} loading={loading} setLoading={setLoading} />,
    signup: <SignupPage setCurrentPage={setCurrentPage} loading={loading} setLoading={setLoading} />,
    store: <StorePage setCurrentPage={setCurrentPage} currentUser={currentUser} handleLogout={handleLogout} />,
    worklog: <WorkLogPage setCurrentPage={setCurrentPage} currentUser={currentUser} loading={loading} setLoading={setLoading} />,
    sales: <SalesPage setCurrentPage={setCurrentPage} currentUser={currentUser} loading={loading} setLoading={setLoading} />,
    admin: <AdminPage setCurrentPage={setCurrentPage} handleLogout={handleLogout} loading={loading} setLoading={setLoading} />
  };

  return <main className="min-h-screen bg-gray-50">{pages[currentPage]}</main>;
}

function MainPage({ setCurrentPage }: any) {
  return (
    <div className="min-h-screen flex flex-col bg-white px-4 py-3">
      <div className="text-right mb-2"><button className="text-teal-600 text-sm">나가기</button></div>
      <div className="flex-1 flex flex-col items-center justify-center max-w-sm mx-auto w-full">
        <div className="text-center mb-8">
          <div className="w-32 mx-auto mb-4">
            <svg viewBox="0 0 200 200" className="w-full h-auto">
              <polygon points="50,30 90,50 90,90 50,70" fill="#2C5F6F"/>
              <polygon points="90,50 130,30 130,70 90,90" fill="#2C5F6F"/>
              <polygon points="50,70 90,90 90,130 50,110" fill="#36B5B0"/>
              <polygon points="90,90 130,70 130,110 90,130" fill="#36B5B0"/>
              <polygon points="50,110 90,130 90,170 50,150" fill="#36B5B0"/>
              <polygon points="90,130 130,110 130,150 90,170" fill="#36B5B0"/>
              <polygon points="30,90 50,80 50,140 30,130" fill="#2C5F6F"/>
              <text x="100" y="195" fontSize="38" fill="#2C5F6F" fontWeight="bold" textAnchor="middle" fontFamily="Arial">LASBOOK</text>
            </svg>
          </div>
          <h1 className="text-2xl font-bold text-teal-700 mb-1">LAS 근무관리시스템</h1>
          <p className="text-xs text-gray-500">출판사 매장 및 판매 관리</p>
        </div>
        <div className="w-full space-y-3">
          <button onClick={() => setCurrentPage('login')} className="w-full bg-teal-600 text-white py-3 rounded-lg font-semibold hover:bg-teal-700">로그인</button>
          <button onClick={() => setCurrentPage('signup')} className="w-full border-2 border-teal-600 text-teal-600 py-3 rounded-lg font-semibold hover:bg-teal-50">회원가입</button>
        </div>
      </div>
    </div>
  );
}

function LoginPage({ setCurrentPage, setCurrentUser, loading, setLoading }: any) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = async () => {
    setError('');
    if (!email) { setError('이메일을 입력하세요.'); return; }
    setLoading(true);
    try {
      const { data, error } = await supabase.from('users').select('*').eq('email', email);
      if (error) throw error;
      if (!data || data.length === 0) { setError('등록되지 않은 이메일입니다.'); return; }
      if (!data[0].approved) { setError('관리자 승인 대기중입니다.'); return; }
      setCurrentUser(data[0]);
      sessionStorage.setItem('currentUser', JSON.stringify(data[0]));
      setCurrentPage('store');
    } catch (err: any) {
      setError('로그인 오류: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-white px-4 py-6">
      <div className="w-full max-w-sm border-2 border-teal-600 rounded-xl p-6">
        <div className="text-center mb-6">
          <div className="w-24 mx-auto mb-3">
            <svg viewBox="0 0 200 200" className="w-full h-auto">
              <polygon points="50,30 90,50 90,90 50,70" fill="#2C5F6F"/>
              <polygon points="90,50 130,30 130,70 90,90" fill="#2C5F6F"/>
              <polygon points="50,70 90,90 90,130 50,110" fill="#36B5B0"/>
              <polygon points="90,90 130,70 130,110 90,130" fill="#36B5B0"/>
              <polygon points="50,110 90,130 90,170 50,150" fill="#36B5B0"/>
              <polygon points="90,130 130,110 130,150 90,170" fill="#36B5B0"/>
              <polygon points="30,90 50,80 50,140 30,130" fill="#2C5F6F"/>
              <text x="100" y="195" fontSize="38" fill="#2C5F6F" fontWeight="bold" textAnchor="middle" fontFamily="Arial">LASBOOK</text>
            </svg>
          </div>
          <p className="text-teal-600 text-xs mb-3">LAS 매장관리 시스템</p>
          <h1 className="text-2xl font-bold text-teal-700">로그인</h1>
        </div>
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 mb-4">
          <p className="text-xs font-semibold text-blue-700">✅ Supabase 연동</p>
          <p className="text-xs text-blue-600">test@test.com 또는 manager@test.com</p>
        </div>
        {error && <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4"><p className="text-xs text-red-600">{error}</p></div>}
        <div className="space-y-3">
          <div>
            <label className="text-xs font-semibold mb-1 block text-gray-900">📧 이메일</label>
            <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleLogin()} disabled={loading} placeholder="이메일을 입력하세요"  className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          </div>
          <div>
            <label className="text-xs font-semibold mb-1 block text-gray-900">🔒 비밀번호</label>
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleLogin()} disabled={loading} placeholder="비밀번호"  className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          </div>
          <div className="flex gap-2 pt-3">
            <button onClick={handleLogin} disabled={loading} className="flex-1 bg-teal-600 text-white py-2.5 rounded-lg font-semibold text-sm">{loading ? '로그인 중...' : '로그인'}</button>
            <button onClick={() => setCurrentPage('main')} className="flex-1 border-2 border-gray-300 py-2.5 rounded-lg font-semibold text-sm">취소</button>
          </div>
        </div>
      </div>
    </div>
  );
}

function SignupPage({ setCurrentPage, loading, setLoading }: any) {
  const [formData, setFormData] = useState({ email: '', password: '', passwordConfirm: '', name: '', storeName: '', phone: '', userType: '점주' });
  const [agreed, setAgreed] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);

  const handleSignup = async () => {
    setError('');
    if (!agreed) { setError('개인정보 동의 필요'); return; }
    if (!formData.email || !formData.password || !formData.name || !formData.storeName) { setError('필수 항목 입력'); return; }
    if (formData.password !== formData.passwordConfirm) { setError('비밀번호 불일치'); return; }
    setLoading(true);
    try {
      const { data: exist } = await supabase.from('users').select('*').eq('email', formData.email);
      if (exist && exist.length > 0) { setError('이미 등록된 이메일'); return; }
      const { error } = await supabase.from('users').insert([{ email: formData.email, name: formData.name, store_name: formData.storeName, phone: formData.phone, user_type: formData.userType, approved: false }]);
      if (error) throw error;
      setSuccess(true);
      setTimeout(() => setCurrentPage('login'), 2000);
    } catch (err: any) {
      setError('오류: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  if (success) return (<div className="min-h-screen flex items-center justify-center px-4"><div className="max-w-sm bg-green-50 border-2 border-green-500 rounded-xl p-8 text-center"><div className="text-5xl mb-4">✅</div><h2 className="text-xl font-bold text-green-700">회원가입 완료!</h2></div></div>);

  return (
    <div className="min-h-screen flex items-center justify-center bg-white px-4 py-6">
      <div className="w-full max-w-sm border-2 border-teal-600 rounded-xl p-5">
        <div className="text-center mb-4">
          <h1 className="text-2xl font-bold text-teal-700">회원가입</h1>
        </div>
        {error && <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4"><p className="text-xs text-red-600">{error}</p></div>}
        <div className="space-y-2.5">
          <input type="email" value={formData.email} onChange={(e) => setFormData({...formData, email: e.target.value})} placeholder="이메일" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <input type="password" value={formData.password} onChange={(e) => setFormData({...formData, password: e.target.value})} placeholder="비밀번호" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <input type="password" value={formData.passwordConfirm} onChange={(e) => setFormData({...formData, passwordConfirm: e.target.value})} placeholder="비밀번호 확인" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} placeholder="이름" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <input type="text" value={formData.storeName} onChange={(e) => setFormData({...formData, storeName: e.target.value})} placeholder="지점명" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <input type="tel" value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})} placeholder="핸드폰" className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm text-gray-900" />
          <div className="flex gap-4">
            <label><input type="radio" value="점주" checked={formData.userType === '점주'} onChange={(e) => setFormData({...formData, userType: e.target.value})} className="mr-1.5" />점주</label>
            <label><input type="radio" value="점장" checked={formData.userType === '점장'} onChange={(e) => setFormData({...formData, userType: e.target.value})} className="mr-1.5" />점장</label>
          </div>
          <div className="bg-gray-50 p-3 rounded-lg"><label className="flex items-start"><input type="checkbox" checked={agreed} onChange={(e) => setAgreed(e.target.checked)} className="mt-0.5 mr-2" /><span className="text-xs">개인정보 동의</span></label></div>
          <div className="flex gap-2">
            <button onClick={handleSignup} disabled={loading} className="flex-1 bg-teal-600 text-white py-2.5 rounded-lg font-semibold text-sm">{loading ? '가입 중...' : '회원가입'}</button>
            <button onClick={() => setCurrentPage('main')} className="flex-1 border-2 border-gray-300 py-2.5 rounded-lg font-semibold text-sm">취소</button>
          </div>
        </div>
      </div>
    </div>
  );
}

